-- OpenResty Lua script to handle user permissions and authentication tokens
local jwt = require 'resty.jwt' -- JWT library for decoding the token

-- Function to validate a token
function validate_token(req)
    local auth_header = req:get_headers()["authorization"]
    
    if not auth_header then
        return false, "No authorization header"
    end
  
    -- Extract the token from the header
    local scheme, token = string.match(auth_header, "^%s*(%w+)%s+(.+)$")
    
    if not scheme or (scheme ~= "Bearer") then
        return false, "Invalid authorization scheme"
    end
  
    -- Decode the token using JWT library
    local decoded_token = jwt:decode(token)
  
    if not decoded_token then
        return false, "Failed to decode token"
    end
    
    return true, decoded_token
end

-- Function to check user permissions based on roles
function check_permissions(req, role)
    local is_valid, decoded_token = validate_token(req)
  
    if not is_valid then
        ngx.status = 401 -- Unauthorized status code
        ngx.say("Unauthorized: ", decoded_token or "")
        return false
    end
    
    local user_role = decoded_token["role"]
  
    if not user_role then
        ngx.status = 403 -- Forbidden status code
        ngx.say("Forbidden: No role provided in the token")
        return false
    end
    
    if user_role ~= role then
        ngx.status = 403 -- Forbidden status code
        ngx.say("Forbidden: User does not have required permissions")
        return false
    end
  
    return true
end

-- Main function to handle the request
function handler(req)
    local uri = req:get_uri()
    
    -- Skip permission checks for certain endpoints
    if string.match(uri, "/admin") or string.match(uri, "/api") then
        return true
    end
  
    -- Check user permissions based on roles
    local is_permitted = check_permissions(req, "required_role")
    
    return is_permitted
end